use std::collections::hash_map::DefaultHasher;
use std::hash::{Hash, Hasher};

const CAPACITY: usize = 64;

#[derive(Clone)]
enum Entry {
    Empty,
    Occupied(String, String),
    Deleted,
}

pub struct HashMap {
    buckets: Vec<Entry>,
    len: usize,
}

impl HashMap {
    pub fn new() -> Self {
        HashMap {
            buckets: vec![Entry::Empty; CAPACITY],
            len: 0,
        }
    }

    fn hash_index(&self, key: &str) -> usize {
        let mut hasher = DefaultHasher::new();
        key.hash(&mut hasher);
        hasher.finish() as usize % CAPACITY
    }

    pub fn insert(&mut self, key: String, value: String) {
        let mut idx = self.hash_index(&key);
        for _ in 0..CAPACITY {
            match &self.buckets[idx] {
                Entry::Empty | Entry::Deleted => {
                    self.buckets[idx] = Entry::Occupied(key, value);
                    self.len += 1;
                    return;
                }
                Entry::Occupied(k, _) if k == &key => {
                    self.buckets[idx] = Entry::Occupied(key, value);
                    return;
                }
                _ => idx = (idx + 1) % CAPACITY,
            }
        }
    }

    pub fn get(&self, key: &str) -> Option<&str> {
        let mut idx = self.hash_index(key);
        for _ in 0..CAPACITY {
            match &self.buckets[idx] {
                Entry::Occupied(k, v) if k == key => return Some(v),
                Entry::Empty => return None,
                _ => idx = (idx + 1) % CAPACITY,
            }
        }
        None
    }

    pub fn remove(&mut self, key: &str) -> bool {
        let mut idx = self.hash_index(key);
        for _ in 0..CAPACITY {
            match &self.buckets[idx] {
                Entry::Occupied(k, _) if k == key => {
                    self.buckets[idx] = Entry::Deleted;
                    self.len -= 1;
                    return true;
                }
                Entry::Empty => return false,
                _ => idx = (idx + 1) % CAPACITY,
            }
        }
        false
    }

    pub fn len(&self) -> usize {
        self.len
    }
}
